const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

const FIRST_INSURANCE_NUMERATOR = 11;
const FIRST_INSURANCE_DENOMINATOR = 10;
const PROCESSING_FEE = 5;

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
    const withFirstInsurance =
      (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
    const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
    return { premium };
  });
  return { results };
};
